import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        int[][] input = {{1,3},{2,6},{8,10},{15,18}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(3, result.length);
        assertArrayEquals(new int[]{1,6},  result[0]);
        assertArrayEquals(new int[]{8,10}, result[1]);
        assertArrayEquals(new int[]{15,18},result[2]);
    }

    @Test
    void touchingIntervals() {
        // [1,4] and [4,5] share the endpoint 4 — must merge into [1,5]
        int[][] input = {{1,4},{4,5}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(1, result.length);
        assertArrayEquals(new int[]{1,5}, result[0]);
    }

    @Test
    void noOverlap() {
        // gap of 1 between 4 and 5 — no merge
        int[][] input = {{1,4},{5,6}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(2, result.length);
        assertArrayEquals(new int[]{1,4}, result[0]);
        assertArrayEquals(new int[]{5,6}, result[1]);
    }

    @Test
    void unsortedInput() {
        // input not sorted by start; method must sort first, then merge
        int[][] input = {{2,3},{1,4},{5,6}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(2, result.length);
        assertArrayEquals(new int[]{1,4}, result[0]);
        assertArrayEquals(new int[]{5,6}, result[1]);
    }

    @Test
    void allOverlap() {
        // all intervals collapse into one
        int[][] input = {{1,10},{2,5},{3,7}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(1, result.length);
        assertArrayEquals(new int[]{1,10}, result[0]);
    }

    @Test
    void singleInterval() {
        int[][] input = {{3,5}};
        int[][] result = new Solution().mergeIntervals(input);
        assertEquals(1, result.length);
        assertArrayEquals(new int[]{3,5}, result[0]);
    }

    @Test
    void empty() {
        int[][] result = new Solution().mergeIntervals(new int[][]{});
        assertEquals(0, result.length);
    }
}
